function parseCSV(raw) {
  if (!raw || !String(raw).trim()) return [];
  const text = String(raw).replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  const rows = [];
  let row = [];
  let field = '';
  let i = 0;
  let inQuotes = false;

  while (i < text.length) {
    const ch = text[i];

    if (inQuotes) {
      if (ch === '"') {
        if (text[i + 1] === '"') {
          field += '"';
          i += 2;
          continue;
        }
        inQuotes = false;
        i += 1;
        continue;
      }
      field += ch;
      i += 1;
      continue;
    }

    if (ch === '"') {
      inQuotes = true;
      i += 1;
      continue;
    }

    if (ch === ',') {
      row.push(field);
      field = '';
      i += 1;
      continue;
    }

    if (ch === '\n') {
      row.push(field);
      field = '';
      rows.push(row);
      row = [];
      i += 1;
      continue;
    }

    field += ch;
    i += 1;
  }

  row.push(field);
  if (row.length > 1 || row[0] !== '') rows.push(row);
  if (rows.length === 0) return [];

  const header = rows[0].map(h => String(h || '').trim());
  return rows.slice(1)
    .filter(r => r.some(v => String(v || '').trim() !== ''))
    .map(r => {
      const obj = {};
      header.forEach((h, idx) => {
        obj[h] = r[idx] ?? '';
      });
      return obj;
    });
}

const allInputs = $input.all();
const bottlesRaw = allInputs[0]?.json?.data || '';
const notesRaw = allInputs[1]?.json?.data || '';

if (!bottlesRaw || !String(bottlesRaw).trim()) {
  throw new Error('Bottles CSV input is empty');
}

const bottles = parseCSV(bottlesRaw);
const notes = parseCSV(notesRaw);

const notesByWine = {};
for (const n of notes) {
  const id = (n.iWine || n.iwine || '').toString().trim();
  if (!id) continue;

  if (!notesByWine[id]) {
    notesByWine[id] = { texts: [], latestDate: null };
  }

  const noteText = String(n.Note || '').trim();
  if (noteText) notesByWine[id].texts.push(noteText);

  const dateText = String(n.Date || '').trim();
  if (dateText) {
    const d = new Date(dateText);
    if (!Number.isNaN(d.getTime())) {
      const cur = notesByWine[id].latestDate ? new Date(notesByWine[id].latestDate) : null;
      if (!cur || d > cur) notesByWine[id].latestDate = dateText;
    }
  }
}

const toInt = (v) => {
  if (v === '' || v == null) return null;
  const n = parseInt(v, 10);
  return Number.isFinite(n) ? n : null;
};

const toFloat = (v) => {
  if (v === '' || v == null) return null;
  const n = parseFloat(v);
  return Number.isFinite(n) ? n : null;
};

const toStr = (v) => {
  if (v === '' || v == null) return null;
  const s = String(v).trim();
  return s === '' ? null : s;
};

const output = [];

for (const row of bottles) {
  const ct_ibottle = toStr(row.Barcode || row.barcode);
  const ct_iwine = toInt(row.iWine || row.iwine);

  if (!ct_ibottle) continue;
  if (String(row.BottleState || '').trim() && String(row.BottleState).trim() !== '1') continue;

  const noteData = notesByWine[String(ct_iwine || '')] || { texts: [], latestDate: null };
  const my_notes = noteData.texts.length ? noteData.texts.join(' | ') : null;

  const parts = [
    toStr(row.Wine),
    (toInt(row.Vintage) && String(row.Vintage) !== '0') ? ('Vintage ' + row.Vintage) : null,
    toStr(row.Producer),
    toStr(row.Type),
    toStr(row.Color),
    toStr(row.Category),
    toStr(row.Locale),
    toStr(row.Appellation),
    toStr(row.Region),
    toStr(row.Country),
    toStr(row.Location) ? ('Location: ' + row.Location) : null,
    toStr(row.Bin) ? ('Bin: ' + row.Bin) : null,
    (toInt(row.BeginConsume) && toInt(row.EndConsume)) ? ('Drink ' + row.BeginConsume + '-' + row.EndConsume) : null,
    (toFloat(row.CT) != null) ? ('CellarTracker score ' + row.CT) : null,
    (toFloat(row.MyScore) != null) ? ('My score ' + row.MyScore) : null,
    (toFloat(row.PurchasePrice) != null) ? ('Purchased at $' + row.PurchasePrice) : null,
    my_notes ? ('Tasting notes: ' + my_notes) : null
  ].filter(Boolean);

  output.push({
    json: {
      ct_ibottle,
      ct_barcode: ct_ibottle,
      ct_iwine,
      wine: toStr(row.Wine),
      vintage: toInt(row.Vintage),
      producer: toStr(row.Producer),
      wine_type: toStr(row.Type),
      color: toStr(row.Color),
      varietal: toStr(row.Category),
      appellation: toStr(row.Appellation),
      region: toStr(row.Region),
      country: toStr(row.Country),
      locale: toStr(row.Locale),
      location: toStr(row.Location),
      bin: toStr(row.Bin),
      purchase_price: toFloat(row.PurchasePrice),
      valuation: toFloat(row.Valuation),
      drink_from: toInt(row.BeginConsume),
      drink_to: toInt(row.EndConsume),
      ct_score: toFloat(row.CT),
      my_score: toFloat(row.MyScore),
      my_notes,
      note_date: noteData.latestDate || null,
      removed_at: null,
      last_synced_at: new Date().toISOString(),
      raw_ct_row: JSON.stringify(row),
      embedding_text: parts.join('. ')
    }
  });
}

return output;

const items = $input.all();
const activeBottles = Array.from(new Set(
  items.map(i => i.json.ct_ibottle).filter(Boolean)
));
return [{
  json: {
    active_bottles: activeBottles,
    count: activeBottles.length
  }
}];

const items = $input.all();
if (!items.length) return [];

const source_items = items.map(i => i.json);
const input = source_items.map(i => i.embedding_text || '');

return [{
  json: {
    batch_count: source_items.length,
    source_items,
    request_body: {
      model: 'openai/text-embedding-3-small',
      input
    }
  }
}];

const resp = $json;
const prep = $('Build Embedding Batch Request').first().json;
const sourceItems = prep.source_items || [];
const data = Array.isArray(resp.data) ? resp.data : [];

if (data.length !== sourceItems.length) {
  throw new Error(`Embedding count mismatch. Expected ${sourceItems.length}, got ${data.length}`);
}

return sourceItems.map((wine, idx) => {
  const embedding = data[idx]?.embedding;
  if (!Array.isArray(embedding)) {
    throw new Error(`Missing embedding for batch index ${idx} (${wine.wine || 'unknown wine'})`);
  }

  const result = { ...wine };
  result.embedding = '[' + embedding.join(',') + ']';
  delete result.embedding_text;
  return { json: result };
});

const upsertCount = $('Build Supabase Upsert Payload').first().json.count || 0;
const today = new Date().toISOString().slice(0, 10);

const summary =
  'Wine inventory sync ' +
  today +
  ': ' +
  upsertCount +
  ' active bottles synced from CellarTracker. Purchase preference inference complete.';

return [{ json: { summary } }];
